SPARQL Query:
PREFIX pko-ind: <https://w3id.org/pko/industry#> 
PREFIX pplan: <http://purl.org/net/p-plan#> 

SELECT *
WHERE {
?step a pplan:Step ;
pko-ind:requiresPPE ?ppe .
}

PREFIX pko-ind: <https://w3id.org/pko/industry#> 
PREFIX pplan: <http://purl.org/net/p-plan#> 

SELECT *
WHERE {
?step a pplan:Step ;
pko-ind:requiresPadlock ?padlock .
}

PREFIX pko-ind: <https://w3id.org/pko/industry#> 

SELECT *
WHERE {
?machine a pko-ind:Machine ;
pko-ind:wasManufacturedBy ?manufacturer .
}

PREFIX pko-ind: <https://w3id.org/pko/industry#> 
PREFIX prov: <http://www.w3.org/ns/prov#> 

SELECT *
WHERE {
?machine a pko-ind:Machine ;
prov:atLocation ?location .
}

PREFIX pko-ind: <https://w3id.org/pko/industry#> 
PREFIX prov: <http://www.w3.org/ns/prov#> 

SELECT *
WHERE {
?machine a pko-ind:Machine ;
prov:atLocation ?factory .
?factory a pko-ind:Factory .
}

PREFIX pko-ind: <https://w3id.org/pko/industry#> 

SELECT *
WHERE {
?machine a pko-ind:Machine ;
pko-ind:hasMachineType ?machineType .
}

PREFIX pko-ind: <https://w3id.org/pko/industry#> 
PREFIX prov: <http://www.w3.org/ns/prov#> 

SELECT *
WHERE {
?activity a prov:Activity ;
pko-ind:isExecutedOnMachine ?machine .
}
